+  fn: (item: A) => Task<T, E>
+): (items: Iterable<A>) => Task<T[], E>;
+export function traverseSerial<A, T, E>(
+  itemsOrFn: Iterable<A> | ((item: A) => Task<T, E>),
+  taskFn?: (item: A) => Task<T, E>
+): Task<T[], E> | ((items: Iterable<A>) => Task<T[], E>) {
+  if (taskFn === undefined) return (items) => traverseSerial(items, itemsOrFn as (item: A) => Task<T, E>);
+  return new Task((resolve, reject) => {
+    void (async () => {
+      const values: T[] = [];
+      for (const item of itemsOrFn as Iterable<A>) {
+        const outcome = await taskFn(item);
+        if (outcome.isErr) {
+          reject(outcome.error);
+          return;
+        }
+        values.push(outcome.value);
+      }
+      resolve(values);
+    })();
+  });
