+  maybeFn?: (error: E) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  return maybeFn === undefined
+    ? (task) => task.inspectRejected(taskOrFn as (error: E) => void)
+    : (taskOrFn as Task<T, E>).inspectRejected(maybeFn);
