+export function sequenceMaybeAsResult<T extends {}, E>(
+  errValue: E,
+  maybes?: Iterable<Maybe<T>>
+): Result<T[], E> | ((maybes: Iterable<Maybe<T>>) => Result<T[], E>) {
+  const op = (items: Iterable<Maybe<T>>) => {
+    const values: T[] = [];
+    for (const maybe of items) {
+      if (maybe.isNothing) return Result.err<T[], E>(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok<T[], E>(values);
+  };
+  return curry1(op, maybes);
+}
+
+export function traverseMaybeAsResult<A, T extends {}, E>(
+  errValue: E,
+  items: Iterable<A>,
+  fn: (item: A) => Maybe<T>
+): Result<T[], E>;
+export function traverseMaybeAsResult<E>(
+  errValue: E
+): <A, T extends {}>(items: Iterable<A>, fn: (item: A) => Maybe<T>) => Result<T[], E>;
+export function traverseMaybeAsResult<A, T extends {}, E>(
+  errValue: E,
+  items?: Iterable<A>,
+  maybeFn?: (item: A) => Maybe<T>
+): Result<T[], E> | ((items: Iterable<A>, fn: (item: A) => Maybe<T>) => Result<T[], E>) {
+  const op = (values: Iterable<A>, fn: (item: A) => Maybe<T>) => {
+    const collected: T[] = [];
+    for (const item of values) {
+      const maybe = fn(item);
+      if (maybe.isNothing) return Result.err<T[], E>(errValue);
+      collected.push(maybe.value);
+    }
+    return Result.ok<T[], E>(collected);
+  };
+  return items === undefined || maybeFn === undefined ? op.bind(undefined) : op(items, maybeFn);
+}
+
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(
+  errValue: E,
+  a: Maybe<A>,
+  b: Maybe<B>
+): Result<[A, B], E>;
+export function zipMaybeAsResult<E>(
+  errValue: E
+): <A extends {}, B extends {}>(a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>;
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(
+  errValue: E,
+  a?: Maybe<A>,
+  b?: Maybe<B>
+): Result<[A, B], E> | ((a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>) {
+  const op = (first: Maybe<A>, second: Maybe<B>) =>
+    first.isJust && second.isJust
+      ? Result.ok<[A, B], E>([first.value, second.value])
