+import {
+  sequenceMaybeAsResult,
+  traverseMaybeAsResult,
+  zipMaybeAsResult,
+} from 'true-myth/toolbelt';
+
+describe('collection composition', () => {
+  test('Maybe and Result iterate only their successful values', () => {
+    expect([...maybe.just(1)]).toEqual([1]);
+    expect([...maybe.nothing<number>()]).toEqual([]);
+    expect([...result.ok<number, string>(1)]).toEqual([1]);
+    expect([...result.err<number, string>('no')]).toEqual([]);
+  });
+
+  test('Maybe sequence and traverse short-circuit generic iterables', () => {
+    let advanced = 0;
+    function* values() {
+      advanced += 1;
+      yield maybe.just(1);
+      advanced += 1;
+      yield maybe.nothing<number>();
+      advanced += 1;
+      yield maybe.just(3);
+    }
+
+    expect(maybe.sequence(values())).toEqual(maybe.nothing());
+    expect(advanced).toBe(2);
+    expect(maybe.traverse([1, 2], (n) => maybe.of(n > 1 ? null : n))).toEqual(maybe.nothing());
+    expect(maybe.compact([maybe.just(1), maybe.nothing<number>()])).toEqual([1]);
+    expect(maybe.filterMap((n: number) => maybe.of(n % 2 ? n : null))([1, 2, 3])).toEqual([1, 3]);
+    expect(maybe.firstJust([maybe.nothing<number>(), maybe.just(2)])).toEqual(maybe.just(2));
+  });
+
+  test('Result helpers preserve errors and split results', () => {
+    expect(result.sequence([result.ok<number, string>(1), result.err<number, string>('no')])).toEqual(
+      result.err('no')
+    );
+    expect(result.zipWith(result.ok<number, string>(2), result.ok<number, string>(3), (a, b) => a + b)).toEqual(
+      result.ok(5)
+    );
+    expect(result.partition([result.ok<number, string>(1), result.err<number, string>('no')])).toEqual([
+      [1],
+      ['no'],
+    ]);
+  });
+
+  test('Task iteration, serial traversal, tapping, and retrying retain task results', async () => {
+    expect(await Array.fromAsync(task.resolve<number, string>(1))).toEqual([result.ok(1)]);
+    const calls: number[] = [];
+    const serial = task.traverseSerial([1, 2, 3], (n) => {
+      calls.push(n);
+      return n === 2 ? task.reject<number, string>('no') : task.resolve<number, string>(n);
+    });
+    expect(await serial).toEqual(result.err('no'));
+    expect(calls).toEqual([1, 2]);
+
+    const seen: number[] = [];
+    expect(await task.tap(task.resolve<number, string>(1), (n) => seen.push(n))).toEqual(result.ok(1));
+    expect(seen).toEqual([1]);
+
+    let attempts = 0;
+    expect(
+      await task.retryN(2, () => (++attempts < 3 ? task.reject<number, string>('no') : task.resolve<number, string>(3)))
+    ).toEqual(result.ok(3));
+    expect(attempts).toBe(3);
+  });
+
+  test('toolbelt converts Nothing to the supplied error', () => {
+    expect(sequenceMaybeAsResult('missing', [maybe.just(1), maybe.nothing<number>()])).toEqual(
+      result.err('missing')
+    );
+    expect(traverseMaybeAsResult('missing')([1], () => maybe.nothing<number>())).toEqual(result.err('missing'));
+    expect(zipMaybeAsResult('missing')(maybe.just(1), maybe.just(2))).toEqual(result.ok([1, 2]));
+  });
